    ---Returns a substring of a specified length starting at a specified position.\
    ---\
    ---Example:\
    ---// Get "STRING" text from "MY_STRING"\
    ---subStr = HUD::GET_CHARACTER_FROM_AUDIO_CONVERSATION_FILENAME("MY_STRING", 3, 6);
    ---@param text string
    ---@param position integer
    ---@param length integer
    ---@return string
    GET_CHARACTER_FROM_AUDIO_CONVERSATION_FILENAME = function(text, position, length) end,

    ---Returns a substring of a specified length starting at a specified position. The result is guaranteed not to exceed the specified max length.\
    ---\
    ---NOTE: The 'maxLength' parameter might actually be the size of the buffer that is returned. More research is needed. -CL69\
    ---\
    ---Example:\
    ---// Condensed example of how Rockstar uses this function\
    ---strLen = HUD::GET_LENGTH_OF_LITERAL_STRING(MISC::GET_ONSCREEN_KEYBOARD_RESULT());\
    ---subStr = HUD::GET_CHARACTER_FROM_AUDIO_CONVERSATION_FILENAME_WITH_BYTE_LIMIT(MISC::GET_ONSCREEN_KEYBOARD_RESULT(), 0, strLen, 63);\
    ---\
    -----\
    ---\
    ---"fm_race_creator.ysc", line 85115:\
    ---// parameters modified for clarity\
    ---BOOL sub_8e5aa(char *text, int length) {\
    ---    for (i = 0; i <= (length - 2); i += 1) {\
    ---        if (!MISC::ARE_STRINGS_EQUAL(HUD::GET_CHARACTER_FROM_AUDIO_CONVERSATION_FILENAME_WITH_BYTE_LIMIT(text, i, i + 1, 1), " ")) {\
    ---            return FALSE;\
    ---    }\
    ---}\
    ---    return TRUE;\
    ---}
    ---@param text string
    ---@param position integer
    ---@param length integer
    ---@param maxLength integer
    ---@return string
    GET_CHARACTER_FROM_AUDIO_CONVERSATION_FILENAME_WITH_BYTE_LIMIT = function(text, position, length, maxLength) end,

    ---Returns a substring that is between two specified positions. The length of the string will be calculated using (endPosition - startPosition).\
    ---\
    ---Example:\
    ---// Get "STRING" text from "MY_STRING"\
    ---subStr = HUD::GET_CHARACTER_FROM_AUDIO_CONVERSATION_FILENAME_BYTES("MY_STRING", 3, 9);\
    ---// Overflows are possibly replaced with underscores (needs verification)\
    ---subStr = HUD::GET_CHARACTER_FROM_AUDIO_CONVERSATION_FILENAME_BYTES("MY_STRING", 3, 10); // "STRING_"?
    ---@param text string
    ---@param startPosition integer
    ---@param endPosition integer
    ---@return string
    GET_CHARACTER_FROM_AUDIO_CONVERSATION_FILENAME_BYTES = function(text, startPosition, endPosition) end,

