    ---The "shape" parameters control the shape of the ped's face. The "skin" parameters control the skin tone. ShapeMix and skinMix control how much the first and second IDs contribute,(typically mother and father.) ThirdMix overrides the others in favor of the third IDs. IsParent is set for "children" of the player character's grandparents during old-gen character creation. It has unknown effect otherwise.\
    ---\
    ---The IDs start at zero and go Male Non-DLC, Female Non-DLC, Male DLC, and Female DLC.\
    ---\
    ---!!!Can someone add working example for this???\
    ---\
    ---try this:\
    ---       headBlendData headData;\
    ---       GET_PED_HEAD_BLEND_DATA(PLAYER_PED_ID(), &headData);\
    ---\
    ---       SET_PED_HEAD_BLEND_DATA(PLAYER_PED_ID(), headData.shapeFirst, headData.shapeSecond, headData.shapeThird, headData.skinFirst, headData.skinSecond\
    ---          , headData.skinThird, headData.shapeMix, headData.skinMix, headData.skinThird, 0);\
    ---\
    ---\
    ---For more info please refer to this topic. \
    ---gtaforums.com/topic/858970-all-gtao-face-ids-pedset-ped-head-blend-data-explained
    ---@param ped Ped
    ---@param shapeFirstID integer
    ---@param shapeSecondID integer
    ---@param shapeThirdID integer
    ---@param skinFirstID integer
    ---@param skinSecondID integer
    ---@param skinThirdID integer
    ---@param shapeMix number
    ---@param skinMix number
    ---@param thirdMix number
    ---@param isParent BOOL
    SET_PED_HEAD_BLEND_DATA = function(ped, shapeFirstID, shapeSecondID, shapeThirdID, skinFirstID, skinSecondID, skinThirdID, shapeMix, skinMix, thirdMix, isParent) end,

    ---The pointer is to a padded struct that matches the arguments to SET_PED_HEAD_BLEND_DATA(...). There are 4 bytes of padding after each field.\
    ---pass this struct in the second parameter \
    ---struct headBlendData\
    ---{\
    ---    int shapeFirst;\
    ---    int padding1;\
    ---    int shapeSecond;\
    ---    int padding2;\
    ---    int shapeThird;\
    ---    int padding3;\
    ---    int skinFirst;\
    ---    int padding4;\
    ---    int skinSecond;\
    ---    int padding5;\
    ---    int skinThird;\
    ---    int padding6;\
    ---    float shapeMix;\
    ---    int padding7;\
    ---    float skinMix;\
    ---    int padding8;\
    ---    float thirdMix;\
    ---    int padding9;\
    ---    bool isParent;\
    ---};
    ---@param ped Ped
    ---@param headBlendData Any*
    ---@return BOOL
    GET_PED_HEAD_BLEND_DATA = function(ped, headBlendData) end,

