PHYSICS = {
    ---Creates a rope at the specific position, that extends in the specified direction when not attached to any entities.\
    ---__\
    ---\
    ---Add_Rope(pos.x,pos.y,pos.z,0.0,0.0,0.0,20.0,4,20.0,1.0,0.0,false,false,false,5.0,false,NULL)\
    ---\
    ---When attached, Position<vector> does not matter\
    ---When attached, Angle<vector> does not matter\
    ---\
    ---Rope Type:\
    ---4 and bellow is a thick rope\
    ---5 and up are small metal wires\
    ---0 crashes the game\
    ---\
    ---Max_length - Rope is forced to this length, generally best to keep this the same as your rope length.\
    ---\
    ---windingSpeed - Speed the Rope is being winded, using native START_ROPE_WINDING. Set positive for winding and negative for unwinding.\
    ---\
    ---Rigid - If max length is zero, and this is set to false the rope will become rigid (it will force a specific distance, what ever length is, between the objects).\
    ---\
    ---breakable - Whether or not shooting the rope will break it.\
    ---\
    ---unkPtr - unknown ptr, always 0 in orig scripts\
    ---__\
    ---\
    ---Lengths can be calculated like so:\
    ---\
    ---float distance = abs(x1 - x2) + abs(y1 - y2) + abs(z1 - z2); // Rope length\
    ---\
    ---\
    ---NOTES:\
    ---\
    ---Rope does NOT interact with anything you attach it to, in some cases it make interact with the world AFTER it breaks (seems to occur if you set the type to -1).\
    ---\
    ---Rope will sometimes contract and fall to the ground like you'd expect it to, but since it doesn't interact with the world the effect is just jaring.
    ---@param x number
    ---@param y number
    ---@param z number
    ---@param rotX number
    ---@param rotY number
    ---@param rotZ number
    ---@param length number
    ---@param ropeType integer
    ---@param maxLength number
    ---@param minLength number
    ---@param windingSpeed number
    ---@param p11 BOOL
    ---@param p12 BOOL
    ---@param rigid BOOL
    ---@param p14 number
    ---@param breakWhenShot BOOL
    ---@param unkPtr Any*
    ---@return integer
    ADD_ROPE = function(x, y, z, rotX, rotY, rotZ, length, ropeType, maxLength, minLength, windingSpeed, p11, p12, rigid, p14, breakWhenShot, unkPtr) end,

    ---@param ropeId integer
    ---@return integer
    DELETE_ROPE = function(ropeId) end,

