SHAPETEST = {
    ---Asynchronously starts a line-of-sight (raycast) world probe shape test.\
    ---\
    ---Use the handle with 0x3D87450E15D98694 or 0x65287525D951F6BE until it returns 0 or 2.\
    ---\
    ---p8 is a bit mask with bits 1, 2 and/or 4, relating to collider types; 4 should usually be used.
    ---@param x1 number
    ---@param y1 number
    ---@param z1 number
    ---@param x2 number
    ---@param y2 number
    ---@param z2 number
    ---@param flags integer
    ---@param entity Entity
    ---@param p8 integer
    ---@return integer
    START_SHAPE_TEST_LOS_PROBE = function(x1, y1, z1, x2, y2, z2, flags, entity, p8) end,

    ---Does the same as 0x7EE9F5D83DD4F90E, except blocking until the shape test completes.
    ---@param x1 number
    ---@param y1 number
    ---@param z1 number
    ---@param x2 number
    ---@param y2 number
    ---@param z2 number
    ---@param flags integer
    ---@param entity Entity
    ---@param p8 integer
    ---@return integer
    START_EXPENSIVE_SYNCHRONOUS_SHAPE_TEST_LOS_PROBE = function(x1, y1, z1, x2, y2, z2, flags, entity, p8) end,

    ---@param entity Entity
    ---@param flags1 integer
    ---@param flags2 integer
    ---@return integer
    START_SHAPE_TEST_BOUNDING_BOX = function(entity, flags1, flags2) end,

    ---@param x number
    ---@param y number
    ---@param z number
    ---@param dimX number
    ---@param dimY number
    ---@param dimZ number
    ---@param rotX number
    ---@param rotY number
    ---@param rotZ number
    ---@param p9 Any
    ---@param flags integer
    ---@param entity Entity
    ---@param p12 Any
    ---@return integer
    START_SHAPE_TEST_BOX = function(x, y, z, dimX, dimY, dimZ, rotX, rotY, rotZ, p9, flags, entity, p12) end,

    ---@param entity Entity
    ---@param flags1 integer
    ---@param flags2 integer
    ---@return integer
    START_SHAPE_TEST_BOUND = function(entity, flags1, flags2) end,

    ---Raycast from point to point, where the ray has a radius. \
    ---\
    ---flags:\
    ---vehicles=10\
    ---peds =12\
    ---\
    ---Iterating through flags yields many ped / vehicle/ object combinations\
    ---\
    ---p9 = 7, but no idea what it does\
    ---\
    ---Entity is an entity to ignore
    ---@param x1 number
    ---@param y1 number
    ---@param z1 number
    ---@param x2 number
    ---@param y2 number
    ---@param z2 number
    ---@param radius number
    ---@param flags integer
    ---@param entity Entity
    ---@param p9 integer
    ---@return integer
    START_SHAPE_TEST_CAPSULE = function(x1, y1, z1, x2, y2, z2, radius, flags, entity, p9) end,

    ---@param x1 number
    ---@param y1 number
    ---@param z1 number
    ---@param x2 number
    ---@param y2 number
    ---@param z2 number
    ---@param radius number
    ---@param flags integer
    ---@param entity Entity
    ---@param p9 Any
    ---@return integer
    START_SHAPE_TEST_SWEPT_SPHERE = function(x1, y1, z1, x2, y2, z2, radius, flags, entity, p9) end,

    ---Returns a ShapeTest handle that can be used with GET_SHAPE_TEST_RESULT.\
    ---\
    ---In its only usage in game scripts its called with flag set to 511, entity to player_ped_id and flag2 set to 7
    ---@param pVec1 Vector3
    ---@param pVec2 Vector3
    ---@param flag integer
    ---@param entity Entity
    ---@param flag2 integer
    ---@return integer
    START_SHAPE_TEST_MOUSE_CURSOR_LOS_PROBE = function(pVec1, pVec2, flag, entity, flag2) end,

    ---Returns the result of a shape test: 0 if the handle is invalid, 1 if the shape test is still pending, or 2 if the shape test has completed, and the handle should be invalidated.\
    ---\
    ---When used with an asynchronous shape test, this native should be looped until returning 0 or 2, after which the handle is invalidated.
    ---@param shapeTestHandle integer
    ---@param hit BOOL
    ---@param endCoords Vector3
    ---@param surfaceNormal Vector3
    ---@param entityHit Entity
    ---@return integer
    ---@return BOOL
    ---@return Entity
    GET_SHAPE_TEST_RESULT = function(shapeTestHandle, hit, endCoords, surfaceNormal, entityHit) end,

    ---Returns the result of a shape test, also returning the material of any touched surface.\
    ---\
    ---When used with an asynchronous shape test, this native should be looped until returning 0 or 2, after which the handle is invalidated.\
    ---\
    ---Unless the return value is 2, the other return values are undefined.
    ---@param shapeTestHandle integer
    ---@param hit BOOL
    ---@param endCoords Vector3
    ---@param surfaceNormal Vector3
    ---@param materialHash Hash
    ---@param entityHit Entity
    ---@return integer
    ---@return BOOL
    ---@return Hash
    ---@return Entity
    GET_SHAPE_TEST_RESULT_INCLUDING_MATERIAL = function(shapeTestHandle, hit, endCoords, surfaceNormal, materialHash, entityHit) end,

    ---Invalidates the entity handle passed by removing the fwScriptGuid from the entity. This should be used when receiving an ambient entity from shape testing natives, but can also be used for other natives returning an 'irrelevant' entity handle.
    ---@param entityHit Entity
    RELEASE_SCRIPT_GUID_FROM_ENTITY = function(entityHit) end
}

