    ---int: Unknown. Can be 0, 1, 2 or 3.\
    ---\
    ---Example:\
    ---TASK_FLUSH_ROUTE();\
    ---TASK_EXTEND_ROUTE(0f, 0f, 70f);\
    ---TASK_EXTEND_ROUTE(10f, 0f, 70f);\
    ---TASK_EXTEND_ROUTE(10f, 10f, 70f);\
    ---TASK_FOLLOW_POINT_ROUTE(GET_PLAYER_PED(), 1f, 0);
